// ============================================================
// frontend/src/pages/MisSolicitudes.jsx
// Tabla de solicitudes con filtros por estado y badges
// ============================================================
import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { MOCK_SOLICITUDES } from '../services/mockData';
import { SkeletonTable } from '../components/SkeletonLoader';

const FILTROS = ['Todos', 'Pendiente', 'Aprobado', 'Rechazado'];

export default function MisSolicitudes() {
  const [solicitudes, setSolicitudes] = useState([]);
  const [cargando, setCargando] = useState(true);
  const [filtro, setFiltro] = useState('Todos');

  useEffect(() => {
    // Simular carga desde mockData
    const timer = setTimeout(() => {
      setSolicitudes(MOCK_SOLICITUDES);
      setCargando(false);
    }, 700);
    return () => clearTimeout(timer);
  }, []);

  const solicitudesFiltradas = filtro === 'Todos'
    ? solicitudes
    : solicitudes.filter(s => s.estado === filtro);

  return (
    <div>
      {/* Header */}
      <div className="page-header">
        <div>
          <h2 className="page-header__title">Mis Solicitudes</h2>
          <p className="page-header__subtitle">
            Gestiona y revisa tus solicitudes de compra y gasto
          </p>
        </div>
        <Link to="/solicitudes/nueva">
          <button className="btn btn--primary">
            <svg viewBox="0 0 24 24" width="16" height="16" stroke="currentColor" fill="none" strokeWidth="2" strokeLinecap="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
            Nueva Solicitud
          </button>
        </Link>
      </div>

      {/* Filter Tabs */}
      <div className="filter-tabs">
        {FILTROS.map(f => (
          <button
            key={f}
            className={`filter-tab ${filtro === f ? 'filter-tab--active' : ''}`}
            onClick={() => setFiltro(f)}
          >
            {f}
            {f !== 'Todos' && (
              <span style={{ marginLeft: 6, opacity: 0.6 }}>
                ({solicitudes.filter(s => f === 'Todos' || s.estado === f).length})
              </span>
            )}
          </button>
        ))}
      </div>

      {/* Table */}
      {cargando ? (
        <SkeletonTable rows={6} columns={6} />
      ) : solicitudesFiltradas.length === 0 ? (
        <div className="empty-state">
          <div className="empty-state__icon">📋</div>
          <h3 className="empty-state__title">No hay solicitudes</h3>
          <p className="empty-state__desc">
            {filtro === 'Todos'
              ? 'No has creado ninguna solicitud aún. ¡Crea tu primera solicitud!'
              : `No tienes solicitudes con estado "${filtro}".`
            }
          </p>
          {filtro === 'Todos' && (
            <Link to="/solicitudes/nueva" style={{ marginTop: 16 }}>
              <button className="btn btn--primary">Crear Solicitud</button>
            </Link>
          )}
        </div>
      ) : (
        <div className="table-container">
          <table className="data-table">
            <thead>
              <tr>
                <th>Título</th>
                <th>Monto</th>
                <th>Tipo</th>
                <th>Departamento</th>
                <th>Fecha</th>
                <th>Estado</th>
                <th style={{ textAlign: 'right' }}>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {solicitudesFiltradas.map(s => (
                <tr key={s.id}>
                  <td className="td-title">{s.titulo}</td>
                  <td className="td-monto">${Number(s.monto).toLocaleString('es-CO')}</td>
                  <td style={{ textTransform: 'capitalize' }}>{s.tipo}</td>
                  <td>{s.departamento}</td>
                  <td>{new Date(s.fecha).toLocaleDateString('es-CO')}</td>
                  <td>
                    <span className={`badge badge--${s.estado.toLowerCase()}`}>
                      {s.estado}
                    </span>
                  </td>
                  <td style={{ textAlign: 'right' }}>
                    <Link to={`/solicitudes/${s.id}`} className="btn btn--ghost btn--sm">
                      Ver historial →
                    </Link>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
